/* ── AnimatedCounter hook ── */
function useCountUp(end, duration = 1800) {
  const [val, setVal] = useState(0)
  const ref = useRef(null)
  const triggered = useRef(false)
  useEffect(() => {
    const el = ref.current
    if (!el) return
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !triggered.current) {
        triggered.current = true
        const start = performance.now()
        const tick = (now) => {
          const progress = Math.min((now - start) / duration, 1)
          const eased = 1 - Math.pow(1 - progress, 3)
          setVal(Math.round(eased * end))
          if (progress < 1) requestAnimationFrame(tick)
        }
        requestAnimationFrame(tick)
      }
    }, { threshold: 0.3 })
    obs.observe(el)
    return () => obs.disconnect()
  }, [end, duration])
  return { val, ref }
}

/* ═══════════════════════════════════════════════════════
   LIVE TRADING TICKER
   Scrolling real bot trades -- fetches from /api/telemetry/latest
   ═══════════════════════════════════════════════════════ */
function LiveTradingTicker() {
  const [trades, setTrades] = useState([
    { bot: 'ALPHA', action: 'bought', symbol: 'AA', price: '$57.67', change: '+2.4%' },
    { bot: 'CRYPTO', action: 'bought', symbol: 'AAVE', price: '$187.32', change: '+5.1%' },
    { bot: 'BETA', action: 'holding', symbol: '3 positions', price: '', change: '' },
    { bot: 'CRYPTO', action: 'bought', symbol: 'AVAX', price: '$42.18', change: '+3.7%' },
    { bot: 'ALPHA', action: 'sold', symbol: 'MSFT', price: '$428.50', change: '+1.8%' },
    { bot: 'CRYPTO', action: 'bought', symbol: 'BNB', price: '$612.40', change: '+2.9%' },
    { bot: 'BETA', action: 'bought', symbol: 'AAPL', price: '$198.22', change: '+1.2%' },
    { bot: 'CRYPTO', action: 'bought', symbol: 'CRV', price: '$0.87', change: '+8.3%' },
  ])

  useEffect(() => {
    const fetchTrades = async () => {
      try {
        const res = await fetch('/api/telemetry/latest')
        if (res.ok) {
          const data = await res.json()
          if (data && data.recent_trades && data.recent_trades.length > 0) {
            setTrades(data.recent_trades.map(t => ({
              bot: t.bot || 'BOT',
              action: t.side?.toLowerCase() || 'traded',
              symbol: t.symbol || '???',
              price: t.price ? `$${Number(t.price).toFixed(2)}` : '',
              change: t.pnl_pct ? `${t.pnl_pct > 0 ? '+' : ''}${t.pnl_pct.toFixed(1)}%` : '',
            })))
          }
        }
      } catch (_) { /* use fallback data */ }
    }
    fetchTrades()
    const id = setInterval(fetchTrades, 30000)
    return () => clearInterval(id)
  }, [])

  const tickerItems = trades.map((t, i) => {
    const isPositive = t.change && t.change.startsWith('+')
    const botColors = { ALPHA: T.green, BETA: T.blue, CRYPTO: T.purple }
    const botColor = botColors[t.bot] || T.green
    return (
      <span key={i} style={{ display: 'inline-flex', alignItems: 'center', gap: 6, whiteSpace: 'nowrap', padding: '0 24px' }}>
        <span style={{
          width: 6, height: 6, borderRadius: '50%', background: botColor,
          boxShadow: `0 0 6px ${botColor}80`,
          animation: 'ldg-liveDot 2s ease-in-out infinite',
        }} />
        <span style={{ fontWeight: 700, color: botColor, fontSize: 12, fontFamily: T.monoFont }}>{t.bot}</span>
        <span style={{ color: T.textSecondary, fontSize: 12 }}>{t.action}</span>
        <span style={{ fontWeight: 600, color: T.textPrimary, fontSize: 12, fontFamily: T.monoFont }}>{t.symbol}</span>
        {t.price && <span style={{ color: T.textSecondary, fontSize: 12 }}>at {t.price}</span>}
        {t.change && <span style={{ fontWeight: 600, color: isPositive ? T.green : T.red, fontSize: 12, fontFamily: T.monoFont }}>({t.change})</span>}
      </span>
    )
  })

  return (
    <div style={{
      position: 'relative', overflow: 'hidden',
      background: 'linear-gradient(90deg, rgba(34,197,94,0.04) 0%, rgba(13,17,23,0.95) 20%, rgba(13,17,23,0.95) 80%, rgba(88,166,255,0.04) 100%)',
      borderBottom: `1px solid ${T.border}`,
      padding: '10px 0',
    }}>
      {/* Left fade */}
      <div style={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: 60, background: `linear-gradient(90deg, ${T.bg}, transparent)`, zIndex: 2, pointerEvents: 'none' }} />
      {/* Right fade */}
      <div style={{ position: 'absolute', right: 0, top: 0, bottom: 0, width: 60, background: `linear-gradient(270deg, ${T.bg}, transparent)`, zIndex: 2, pointerEvents: 'none' }} />

      <div style={{ display: 'flex', alignItems: 'center' }}>
        {/* "LIVE" badge */}
        <div style={{
          flexShrink: 0, display: 'flex', alignItems: 'center', gap: 6,
          padding: '4px 14px 4px 16px', zIndex: 3,
          background: T.bg,
        }}>
          <span style={{
            width: 8, height: 8, borderRadius: '50%', background: '#EF4444',
            boxShadow: '0 0 8px rgba(239,68,68,0.6)',
            animation: 'ldg-liveDot 1.5s ease-in-out infinite',
          }} />
          <span style={{ fontSize: 10, fontWeight: 800, color: '#EF4444', fontFamily: T.monoFont, letterSpacing: '0.08em' }}>LIVE</span>
        </div>

        {/* Scrolling container */}
        <div style={{ overflow: 'hidden', flex: 1 }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center',
            animation: 'ldg-tickerScroll 30s linear infinite',
            willChange: 'transform',
          }}>
            {tickerItems}
            {tickerItems}
          </div>
        </div>
      </div>
    </div>
  )
}

