/* ── StatCounter helper ── */
function StatCounter({ end, suffix, label, showDivider, highlight }) {
  const { val, ref } = useCountUp(end, 2000)
  const formatted = end >= 1000 ? val.toLocaleString() : val
  return (
    <>
      <div ref={ref} style={{ flex: 1, textAlign: 'center', padding: '8px 16px' }}>
        <div style={{
          fontSize: 32, fontWeight: 800,
          color: highlight ? T.amber : T.green,
          fontFamily: T.monoFont,
          animation: val === end ? 'ldg-numberPop 0.3s ease-out' : 'none',
        }}>{formatted}{suffix}</div>
        <div style={{
          fontSize: 13, color: highlight ? T.amber : T.textSecondary,
          marginTop: 4, textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 600,
        }}>{label}</div>
      </div>
      {showDivider && (
        <div style={{ width: 1, background: T.border, alignSelf: 'stretch', margin: '8px 0' }} />
      )}
    </>
  )
}

